// Parse webhook payload to determine CLI flags.
// Body: { reason: 'sms' | 'incident' | 'manual' }
const body = $input.first().json.body || $input.first().json || {};
const reason = (body.reason || 'manual').toString().toLowerCase();
let flags = ['--reason', reason];
if (reason === 'incident') {
  flags.push('--on-incident');
}
return [{ json: { reason, flags, flagsCli: flags.join(' ') } }];
